# routes.py\nfrom models import SUBSCRIPTIONS, Subscription\n\ndef list_subscriptions():\n    # TODO: serialize to JSON-compatible dicts\n    return [s.__dict__ for s in SUBSCRIPTIONS]\n\ndef create_subscription(payload):\n    # TODO: basic validation of payload\n    sub = Subscription(len(SUBSCRIPTIONS)+1, payload['email'], payload['plan'])\n    SUBSCRIPTIONS.append(sub)\n    return sub.__dict__